const DEFAULT_MEMORY_DIR = join(homedir(), ".pi", "memory");
const DEFAULT_DB_PATH = join(DEFAULT_MEMORY_DIR, "memory.db");
const GLOBAL_SETTINGS_PATH = join(homedir(), ".pi", "agent", "settings.json");

