// consolidate.ts — Session-end LLM extraction of memories
// Reads conversation messages from stdin (JSON array of {role, content}),
// calls LLM to extract facts, decisions, patterns, and writes to brain.
//
// Usage: tsx scripts/consolidate.ts < messages.json
//        pi -p "$(cat prompt.txt)" --print | tsx scripts/consolidate.ts --from-stdin
//
// If called from a Claude Code hook (Stop event), reads transcript_path from stdin JSON.

import { readFileSync } from "node:fs";
import { join } from "node:path";
import { execFileSync } from "node:child_process";
import { BrainStore } from "./store.js";
import { rememberMemory } from "./remember.js";
import type { BrainFileType } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

const CONSOLIDATION_PROMPT = `You are a memory extraction system for Penny, a personal assistant. Analyze this conversation and extract knowledge worth keeping.

Extract ONLY concrete, reusable knowledge — not summaries of what happened. Focus on:

1. **Personal facts about Nik** (preferences, personality, history)
   Example: "Nik prefers Deno over Node for scripting"

2. **Decisions made** (project direction, architecture choices)
