- Categorize each as: fact, decision, project_context, pattern, correction

Respond with ONLY valid JSON:
{
  "memories": [
    {
      "type": "fact|decision|project_context|pattern|correction",
      "category": "people|projects|patterns|sessions|self",
      "content": "The specific memory to store",
      "tags": ["relevant", "tags"]
    }
  ]
}

If nothing worth extracting, return: { "memories": [] }`;

interface Message {
  role: string;
  content: string;
}

interface ExtractedMemory {
  type: string;
  category: string;
  content: string;
  tags: string[];
}

function readMessages(): Message[] {
  // Try reading from stdin
  const stdin = readFileSync(0, "utf-8").trim();
  if (!stdin) {
    console.error("No input on stdin");
    process.exit(1);
  }

  try {
    // Check if it's a Claude Code hook event JSON
    const hookEvent = JSON.parse(stdin);
    if (hookEvent.transcript_path) {
      const transcript = readFileSync(hookEvent.transcript_path, "utf-8");
      return parseTranscript(transcript);
    }
  } catch {
    // Not JSON — try parsing as messages array
  }

  try {
    return JSON.parse(stdin);
  } catch {
    // Treat as plain text conversation
    return [{ role: "user", content: stdin }];
  }
}

function parseTranscript(transcript: string): Message[] {
  const messages: Message[] = [];
  const lines = transcript.split("\n");
  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      if (entry.type === "message" && entry.message) {
        const msg = entry.message;
        if (msg.role === "user" || msg.role === "assistant") {
          const text = typeof msg.content === "string"
            ? msg.content
            : Array.isArray(msg.content)
              ? msg.content.filter((c: { type: string; text?: string }) => c.type === "text").map((c: { type: string; text?: string }) => c.text).join("\n")
              : "";
          if (text) messages.push({ role: msg.role, content: text });
        }
      }
    } catch {
      // skip malformed lines
    }
  }
  return messages;
}

function buildPrompt(messages: Message[]): string {
  const conversation = messages.slice(-40) // last 40 messages
    .map(m => `${m.role === "user" ? "Nik" : "Penny"}: ${m.content.slice(0, 500)}`)
    .join("\n\n");

  return `${CONSOLIDATION_PROMPT}

## Conversation

${conversation}`;
}

function parseResponse(text: string): ExtractedMemory[] {
  // Extract JSON from markdown code block or raw
  const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/) || text.match(/(\{[\s\S]*\})/);
  if (!jsonMatch) return [];

  try {
    const parsed = JSON.parse(jsonMatch[1].trim());
    if (Array.isArray(parsed.memories)) {
      return parsed.memories.filter((m: Record<string, unknown>) =>
        typeof m.content === "string" && m.content.trim().length > 0
      );
    }
  } catch {
    // parse error
  }
  return [];
}

async function consolidate(): Promise<void> {
  const messages = readMessages();
  if (messages.length < 3) {
    console.log("Not enough messages to consolidate (need ≥3)");
    return;
  }

  const prompt = buildPrompt(messages);

  // Call LLM via pi (if available) or log for manual processing
  try {
    const result = execFileSync("pi", ["-p", prompt, "--print", "--no-extensions"], {
      encoding: "utf8",
      timeout: 45_000,
      maxBuffer: 1024 * 1024,
    });

    if (result) {
      const memories = parseResponse(result);
      console.log(`Extracted ${memories.length} memories`);

      for (const mem of memories) {
        const brainType = mapCategoryToType(mem.category);
        await rememberMemory(brainType, mem.content, {
          tags: mem.tags,
          section: mem.type === "correction" ? "Corrections" : "Key Facts",
        });
      }
    }
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    console.error(`LLM consolidation failed: ${msg}`);
    console.log("Prompt saved for manual processing:");
    console.log(prompt);
  }
}

function mapCategoryToType(category: string): BrainFileType {
  switch (category) {
    case "people": return "person";
    case "projects": return "project";
    case "patterns": return "pattern";
    case "sessions": return "session";
    case "self": return "self";
    default: return "daily";
  }
}

consolidate().catch(err => {
  console.error("consolidate failed:", err);
  process.exit(1);
});

#!/usr/bin/env tsx
// detect-memorable.ts — Lightweight post-tool detection of memorables
// Called async from Claude Code PostToolUse hooks.
// Checks if the last turn contained a decision, correction, or insight worth saving.
//
// Uses a short LLM prompt (cheap/fast model) to classify.
// If memorable, calls remember.ts to store.
//
// Input: stdin JSON from Claude Code hook (tool_name, tool_input, cwd)

import { readFileSync, existsSync } from "node:fs";
import { join, dirname } from "node:path";
import { execFileSync } from "node:child_process";
import { rememberMemory } from "./remember.js";
import type { BrainFileType } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");

const DETECTION_PROMPT = `You are a lightweight detector. Analyze this exchange and check if it contains anything Penny should remember.

Look for:
- **Decisions**: "Let's go with X", "We'll use Y"
- **Corrections**: "No, actually...", "That's wrong, it's..."
- **Personal facts**: "I prefer...", "I used to...", "My experience with..."
- **Project insights**: Architecture decisions, problem revelations
- **Strong preferences**: "I hate...", "I love...", "Always do X never Y"

Ignore:
- Routine task execution
- Code that can be read from files
- Temporary state
- Polite conversation

Respond with ONLY JSON:
{
  "memorable": true or false,
  "content": "If true: the specific fact/decision/correction to remember (one sentence)",
  "category": "people|projects|patterns|sessions|self",
  "type": "fact|decision|project_context|pattern|correction"
}

If not memorable, return: { "memorable": false }`;

interface HookInput {
  tool_name?: string;
  tool_input?: Record<string, unknown>;
  transcript_path?: string;
  cwd?: string;
}

function readInput(): HookInput {
  try {
    const stdin = readFileSync(0, "utf-8").trim();
    if (stdin) return JSON.parse(stdin);
  } catch {
    // No stdin or not JSON
  }
  return {};
}

function getLastTurn(transcriptPath: string): string {
  if (!existsSync(transcriptPath)) return "";

  const transcript = readFileSync(transcriptPath, "utf-8");
  const lines = transcript.trim().split("\n");
  // Get last few messages
  const lastMessages: string[] = [];
  const recent = lines.slice(-10);

  for (const line of recent) {
    try {
      const entry = JSON.parse(line);
      if (entry.type === "message" && entry.message) {
        const msg = entry.message;
        const text = typeof msg.content === "string"
          ? msg.content
          : Array.isArray(msg.content)
            ? msg.content.filter((c: { type: string; text?: string }) => c.type === "text").map((c: { type: string; text?: string }) => c.text).join(" ")
            : "";
        if (text && text.length < 1000) {
          lastMessages.push(`${msg.role}: ${text}`);
        }
      }
    } catch {
      // skip
    }
  }

  return lastMessages.join("\n");
}

async function detect(): Promise<void> {
  const input = readInput();

  // Only check after significant tool calls
  const significantTools = ["Write", "Edit", "Bash"];
  if (input.tool_name && !significantTools.includes(input.tool_name)) {
    return; // Skip — not a significant tool call
  }

  // Get last turn from transcript
  const transcriptPath = input.transcript_path;
  if (!transcriptPath) return;

  const lastTurn = getLastTurn(transcriptPath);
  if (!lastTurn || lastTurn.length < 50) return;

  // Build detection prompt
  const prompt = `${DETECTION_PROMPT}

## Recent exchange

${lastTurn}`;

  try {
    // Use pi with a fast model for quick classification
    const result = execFileSync("pi", [
      "-p", prompt,
      "--print",
      "--no-extensions",
      "--model", "claude-haiku-4-5-20251001",
    ], {
      encoding: "utf8",
      timeout: 20_000,
      maxBuffer: 256 * 1024,
      cwd: input.cwd || ROOT_DIR,
    });

    // Parse JSON from response
    const jsonMatch = result.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return;

    const parsed = JSON.parse(jsonMatch[0]);
    if (!parsed.memorable || !parsed.content) return;

    console.log(`Detected memorable: ${parsed.content}`);

    // Store it
    const brainType: BrainFileType = (parsed.category as BrainFileType) || "daily";
    await rememberMemory(brainType, parsed.content, {
      tags: [parsed.type || "fact"],
    });
  } catch (err: unknown) {
    // Detection is best-effort — don't block on failure
    const msg = err instanceof Error ? err.message : String(err);
    if (!msg.includes("command not found")) {
      console.error(`detect-memorable: ${msg}`);
    }
  }
}

detect().catch(() => {
  // Silent failure — detection is non-critical
});

#!/usr/bin/env tsx
// session-start.ts — Inject brain context at session start
// Called from Claude Code SessionStart hook or pi session_start.
// Reads stdin JSON from hook, searches brain for relevant context,
// outputs context block to stdout (which becomes system prompt context).
//
// Usage: Called automatically by hook. No CLI arguments needed.

import { readFileSync } from "node:fs";
import { join } from "node:path";
import { BrainStore } from "./store.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

const MAX_CONTEXT_CHARS = 4000;

interface SessionStartInput {
  session_id?: string;
  cwd?: string;
  hook_event_name?: string;
}

function readInput(): SessionStartInput {
  try {
    const stdin = readFileSync(0, "utf-8").trim();
    if (stdin) return JSON.parse(stdin);
  } catch {
    // no stdin
  }
  return {};
}

function getCwdPrompt(): string {
  // Try to extract a project name from cwd
  try {
    const input = readInput();
    if (input.cwd) {
      const parts = input.cwd.split("/").filter(Boolean);
      const skip = new Set(["Users", "home", "nbr", "repos", "nikbrunner", "workplace"]);
      const relevant = parts.filter(p => !skip.has(p));
      return relevant.join(" ");
    }
  } catch {
    // ignore
  }
  return "";
}

async function buildContext(): Promise<string> {
  const store = new BrainStore(DB_PATH);
  const sections: string[] = [];

  // 1. Penny's self-model (always injected)
  const selfFiles = store.searchByType("penny", "self", 1);
  if (selfFiles.length > 0) {
    sections.push(`## My Self-Model\n${selfFiles[0].excerpt}`);
  }

  // 2. People context (key facts about Nik — always injected)
  const peopleFiles = store.searchByType("nik", "person", 2);
  if (peopleFiles.length > 0) {
    const facts = peopleFiles.map(f => f.excerpt).join("\n");
    sections.push(`## About Nik\n${facts.slice(0, 800)}`);
  }

  // 3. Project context (from cwd)
  const cwdPrompt = getCwdPrompt();
  if (cwdPrompt) {
    const projectResults = store.search(cwdPrompt, 3);
    if (projectResults.length > 0) {
      const projectContext = projectResults.map(r => `- [${r.type}] ${r.excerpt}`).join("\n");
      sections.push(`## Project Context\n${projectContext}`);
    }
  }

  // 4. Recent patterns (last updated)
  const patterns = store.searchByTag("patterns", 5);
  if (patterns.length > 0) {
    const patternContext = patterns.slice(0, 3).map(r => `- ${r.excerpt.slice(0, 150)}`).join("\n");
    sections.push(`## Patterns\n${patternContext}`);
  }

  // 5. Recent sessions (last 7 days)
  const sessions = store.searchByType("session", "session", 3);
  if (sessions.length > 0) {
    const sessionContext = sessions.map(r => `- ${r.title}: ${r.excerpt.slice(0, 100)}`).join("\n");
    sections.push(`## Recent Sessions\n${sessionContext}`);
  }

  // 6. Important lessons (corrections to remember)
  const corrections = store.searchByTag("correction", 5);
  if (corrections.length > 0) {
    const correctionContext = corrections.map(r => `- ${r.excerpt.slice(0, 150)}`).join("\n");
    sections.push(`## Before Acting\n${correctionContext}`);
  }

  store.close();

  if (sections.length === 0) return "";

  let text = `<penny_brain>\n${sections.join("\n\n")}\n\n## Reminder\n- Memory records can become stale. Verify before relying on them.\n- If memory conflicts with what you observe, trust observation.\n</penny_brain>`;

  if (text.length > MAX_CONTEXT_CHARS) {
    text = text.slice(0, MAX_CONTEXT_CHARS - 20) + "\n... (truncated)\n</penny_brain>";
  }

  return text;
}

async function main(): Promise<void> {
  const context = await buildContext();
  if (context) {
    // Output to stdout — Claude Code injects this as context
    console.log(context);
  }
}

main().catch(err => {
  console.error("session-start failed:", err);
  process.exit(1);
});

#!/usr/bin/env tsx
// bootstrap.ts — Absorb existing knowledge from dots and notes repos
// One-time run to seed the brain with everything Penny already "knows"
// from CLAUDE.md, AGENTS.md, and skill files.
//
// Usage: tsx scripts/bootstrap.ts [--force]

import { readFileSync, existsSync, writeFileSync } from "node:fs";
import { join, relative } from "node:path";
import { readdir } from "node:fs/promises";
import { execFileSync } from "node:child_process";
import matter from "gray-matter";
import { rememberMemory } from "./remember.js";
import { today } from "./markdown.js";
import type { BrainFileType } from "./types.js";

const HOME = join(import.meta.dirname, "..", "..", "..", "..", "..");
const DOTS_DIR = join(HOME, "repos", "nikbrunner", "dots");
const NOTES_DIR = join(HOME, "repos", "nikbrunner", "notes");
const SKILLS_DIR = join(DOTS_DIR, "common", ".agents", "skills");
const AGENTS_GLOBAL = join(HOME, ".agents", "AGENTS.md");
const DONE_MARKER = join(import.meta.dirname, "..", ".bootstrap-done");

const BOOTSTRAP_PROMPT = `You are helping Penny, Nik's personal assistant, bootstrap her long-term memory. 
You are reading Nik's existing configuration and personal files and extracting structured knowledge.

## What to Extract

For each section below, extract relevant facts, preferences, and patterns. Be concise.

### Nik's Personality & Background
- Who he is, his background, his values
- How he communicates (dry humor, values authenticity)
- His professional history
- His personal situation (partner Ana, family estrangement, therapy)

### Communication Preferences
- How he wants Penny to talk to him
- What tone, what language
- What to avoid

### Technical Preferences
- Languages, frameworks, tools he prefers
- Coding style, conventions
- Anti-patterns he dislikes

### Projects
- What projects are active
- What each project is about
- Key technical decisions

### Penny's Identity
- Who Penny is supposed to be
- Her personality, boundaries
- Her tools and capabilities

Respond with JSON:
{
  "personality": ["fact 1", "fact 2", ...],
  "technical": ["fact 1", "fact 2", ...],
  "projects": ["fact 1", "fact 2", ...],
  "penny": ["fact 1", "fact 2", ...],
  "patterns": ["fact 1", "fact 2", ...]
}`;

async function readFileSafe(path: string): Promise<string> {
  try {
    return readFileSync(path, "utf-8");
  } catch {
    return "";
  }
}

async function findClaudeAgentsFiles(dir: string): Promise<string[]> {
  const files: string[] = [];
  try {
    const entries = await readdir(dir, { withFileTypes: true, recursive: true });
    for (const entry of entries) {
      if (entry.isFile() && (entry.name === "CLAUDE.md" || entry.name === "AGENTS.md")) {
        files.push(join(entry.parentPath || dir, entry.name));
      }
    }
  } catch {
    // dir doesn't exist
  }
  return files;
}

async function collectSourceText(): Promise<string> {
  const sources: string[] = [];

  // 1. Global AGENTS.md
  const globalAgents = await readFileSafe(AGENTS_GLOBAL);
  if (globalAgents) {
    sources.push(`## Global AGENTS.md\n\n${globalAgents}`);
  }

  // 2. Dots AGENTS.md / CLAUDE.md
  const dotsAgents = await readFileSafe(join(DOTS_DIR, "AGENTS.md"));
  if (dotsAgents) sources.push(`## Dots AGENTS.md\n\n${dotsAgents}`);

  // 3. Notes CLAUDE.md
  const notesClaude = await readFileSafe(join(NOTES_DIR, "CLAUDE.md"));
  if (notesClaude) sources.push(`## Notes CLAUDE.md\n\n${notesClaude}`);

  // 4. All Claude/Agents files in repos
  const moreFiles = await findClaudeAgentsFiles(join(HOME, "repos"));
  for (const file of moreFiles.slice(0, 10)) {
    const content = await readFileSafe(file);
    if (content && content.length > 100) {
      sources.push(`## ${relative(HOME, file)}\n\n${content.slice(0, 3000)}`);
    }
  }

  // 5. Key skills
  const skillsToRead = ["penny-profile", "penny-daily", "about-nik", "about-bai", "about-sonder"];
  for (const skill of skillsToRead) {
    const skillPath = join(SKILLS_DIR, skill, "SKILL.md");
    const content = await readFileSafe(skillPath);
    if (content) {
      sources.push(`## Skill: ${skill}\n\n${content.slice(0, 3000)}`);
    }
  }

  return sources.join("\n\n---\n\n");
}

function parseBootstrapResponse(text: string): Record<string, string[]> {
  const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/) || text.match(/(\{[\s\S]*\})/);
  if (!jsonMatch) return {};

  try {
    const parsed = JSON.parse(jsonMatch[1].trim());
    return parsed;
  } catch {
    return {};
  }
}

async function bootstrap(): Promise<void> {
  if (existsSync(DONE_MARKER) && !process.argv.includes("--force")) {
    console.log("Bootstrap already done. Use --force to re-run.");
    return;
  }

  console.log("Collecting existing knowledge...");
  const sourceText = await collectSourceText();
  console.log(`Collected ${sourceText.length} chars from CLAUDE.md, AGENTS.md, and skills`);

  if (sourceText.length < 200) {
    console.log("Not enough source material found. Skipping LLM extraction.");
    return;
  }

  // Call LLM via pi
  const prompt = `${BOOTSTRAP_PROMPT}\n\n## Source Material\n\n${sourceText.slice(0, 15000)}`;

  console.log("\nExtracting structured knowledge via LLM...");
  try {
    const result = execFileSync("pi", ["-p", prompt, "--print", "--no-extensions"], {
      encoding: "utf8",
      timeout: 60_000,
      maxBuffer: 1024 * 1024,
    });

    const extracted = parseBootstrapResponse(result);
    console.log(`\nLLM returned ${Object.keys(extracted).length} categories`);

    let totalStored = 0;
    for (const [category, facts] of Object.entries(extracted)) {
      if (!Array.isArray(facts)) continue;

      const type = mapCategory(category);
      console.log(`\nStoring ${facts.length} ${category} facts...`);

      for (const fact of facts) {
        if (typeof fact === "string" && fact.trim()) {
          await rememberMemory(type, fact.trim(), {
            tags: [category, "bootstrapped"],
            section: "Key Facts",
          });
          totalStored++;
        }
      }
    }

    console.log(`\n✅ Bootstrap complete! Stored ${totalStored} facts.`);

    // Rebuild index
    console.log("\nRebuilding index...");
    execFileSync("tsx", [join(import.meta.dirname, "sync-index.ts"), "--rebuild"], {
      cwd: join(import.meta.dirname, ".."),
      stdio: "inherit",
    });

    // Mark as done
    writeFileSync(DONE_MARKER, today(), "utf-8");
    console.log("Done! (marker file created, won't re-run unless --force)");
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    console.error(`Bootstrap LLM call failed: ${msg}`);
    console.log("\nYou can run bootstrap manually later with: tsx scripts/bootstrap.ts --force");
  }
}

function mapCategory(category: string): BrainFileType {
  switch (category) {
    case "personality": return "person";
    case "technical": return "pattern";
    case "projects": return "project";
    case "penny": return "self";
    case "patterns": return "pattern";
    default: return "daily";
  }
}

bootstrap().catch(err => {
  console.error("bootstrap failed:", err);
  process.exit(1);
});

#!/usr/bin/env tsx
// dedup.ts — Scan brain for duplicate, stale, and conflicting entries
// Usage: tsx scripts/dedup.ts [--apply]

import { join } from "node:path";
import { writeFileSync } from "node:fs";
import { BrainStore } from "./store.js";
import { scanBrainFiles, readBrainFile, today } from "./markdown.js";
import type { DedupReport } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");
const REPORT_PATH = join(ROOT_DIR, "brain", `_dedup-report-${today()}.md`);

function jaccard(a: string, b: string): number {
  const setA = new Set(a.toLowerCase().split(/\s+/).filter(Boolean));
  const setB = new Set(b.toLowerCase().split(/\s+/).filter(Boolean));
  if (setA.size === 0 && setB.size === 0) return 1;
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);
  return intersection.size / union.size;
}

function extractBullets(content: string): string[] {
  const bullets: string[] = [];
  for (const line of content.split("\n")) {
    const trimmed = line.trim();
    if (trimmed.startsWith("- ") && trimmed.length > 10) {
      bullets.push(trimmed.slice(2));
    }
  }
  return bullets;
}

async function dedup(): Promise<DedupReport> {
  const store = new BrainStore(DB_PATH);
  const files = await scanBrainFiles();

  const duplicates: DedupReport["duplicates"] = [];

  // 1. Check exact duplicate bullets across files
  const bulletMap = new Map<string, string[]>(); // bullet text → file paths
  for (const file of files) {
    const bullets = extractBullets(file.content);
    for (const bullet of bullets) {
      const existing = bulletMap.get(bullet.toLowerCase());
      if (existing) {
        existing.push(file.path);
      } else {
        bulletMap.set(bullet.toLowerCase(), [file.path]);
      }
    }
  }

  for (const [, paths] of bulletMap) {
    if (paths.length > 1) {
      duplicates.push({
        type: "exact",
        files: paths,
        excerpt: paths[0], // the duplicate content
        suggestion: `Merge these files or remove duplicates. Same fact stored in ${paths.length} places.`,
      });
    }
  }

  // 2. Check near-duplicate paragraphs (Jaccard ≥ 0.8)
  for (let i = 0; i < files.length; i++) {
    for (let j = i + 1; j < files.length; j++) {
      const bulletsA = extractBullets(files[i].content);
      const bulletsB = extractBullets(files[j].content);

      for (const bulletA of bulletsA) {
        for (const bulletB of bulletsB) {
          if (jaccard(bulletA, bulletB) >= 0.8 && bulletA !== bulletB) {
            duplicates.push({
              type: "near",
              files: [files[i].path, files[j].path],
              excerpt: `${bulletA.slice(0, 80)}... ≈ ${bulletB.slice(0, 80)}...`,
              suggestion: "These are near-duplicates. Keep the more precise version.",
            });
          }
        }
      }
    }
  }

  // 3. Check for stale entries (unchanged for 90+ days, might be outdated)
  const ninetyDaysAgo = new Date();
  ninetyDaysAgo.setDate(ninetyDaysAgo.getDate() - 90);
  const staleThreshold = ninetyDaysAgo.toISOString().slice(0, 10);

  const staleFiles = files.filter(f => {
    const updated = f.frontmatter.updated || f.frontmatter.date || "";
    return updated && updated < staleThreshold;
  });

  for (const file of staleFiles) {
    duplicates.push({
      type: "stale",
      files: [file.path],
      excerpt: `Last updated: ${file.frontmatter.updated || "unknown"}`,
      suggestion: "This file hasn't been updated in 90+ days. Review for accuracy.",
    });
  }

  // 4. Check for conflicts (contradictory facts) — basic check
  // Look for "prefers X" vs "prefers Y" patterns
  const preferences = new Map<string, string[]>();
  for (const file of files) {
    const bullets = extractBullets(file.content);
    for (const bullet of bullets) {
      const match = bullet.match(/(?:prefers?|uses?|loves?|hates?)\s+(.+)/i);
      if (match) {
        const key = match[0].toLowerCase().replace(/\s+/g, " ").trim();
        const existing = preferences.get(key.split(/\s+/).slice(0, 3).join(" "));
        if (existing) {
          existing.push(`${file.path}: ${bullet}`);
        } else {
          preferences.set(key.split(/\s+/).slice(0, 3).join(" "), [`${file.path}: ${bullet}`]);
        }
      }
    }
  }

  for (const [, entries] of preferences) {
    if (entries.length > 1) {
      const unique = [...new Set(entries.map(e => e.split(": ").slice(1).join(": ")))];
      if (unique.length > 1) {
        duplicates.push({
          type: "conflict",
          files: entries.map(e => e.split(": ")[0]),
          excerpt: unique.join(" vs. "),
          suggestion: "Possible conflict — resolve which is correct, or add context.",
        });
      }
    }
  }

  store.close();

  return {
    duplicates: duplicates.slice(0, 100), // cap
    stats: {
      totalEntries: files.length,
      duplicateGroups: duplicates.filter(d => d.type === "exact" || d.type === "near").length,
      staleEntries: staleFiles.length,
      conflicts: duplicates.filter(d => d.type === "conflict").length,
    },
  };
}

function formatReport(report: DedupReport): string {
  let md = `# Dedup Report — ${today()}\n\n`;
  md += `## Stats\n\n`;
  md += `- Total entries: ${report.stats.totalEntries}\n`;
  md += `- Duplicate groups: ${report.stats.duplicateGroups}\n`;
  md += `- Stale entries: ${report.stats.staleEntries}\n`;
  md += `- Conflicts: ${report.stats.conflicts}\n\n`;

  if (report.duplicates.length === 0) {
    md += `✅ No issues found! Brain is clean.\n`;
    return md;
  }

  md += `## Issues\n\n`;

  const byType = {
    exact: report.duplicates.filter(d => d.type === "exact"),
    near: report.duplicates.filter(d => d.type === "near"),
    stale: report.duplicates.filter(d => d.type === "stale"),
    conflict: report.duplicates.filter(d => d.type === "conflict"),
  };

  for (const [type, items] of Object.entries(byType)) {
    if (items.length === 0) continue;
    md += `### ${type.charAt(0).toUpperCase() + type.slice(1)} (${items.length})\n\n`;
    for (const item of items.slice(0, 20)) {
      md += `- **Files**: ${item.files.join(", ")}\n`;
      md += `  - ${item.excerpt.slice(0, 120)}\n`;
      md += `  - Suggestion: ${item.suggestion}\n\n`;
    }
  }

  return md;
}

async function main(): Promise<void> {
  console.log("Scanning brain for duplicates, stale entries, and conflicts...");
  const report = await dedup();
  const reportMd = formatReport(report);

  writeFileSync(REPORT_PATH, reportMd, "utf-8");
  console.log(`Report saved to ${REPORT_PATH}`);
  console.log(`\n${reportMd}`);
}

main().catch(err => {
  console.error("dedup failed:", err);
  process.exit(1);
});

/**
 * third-brain Pi extension — Penny's long-term memory
 *
 * Hooks into pi lifecycle to:
 * - Inject brain context at session start
 * - Collect messages for consolidation
 * - Provide memory tools (remember, recall, forget, stats)
 */

import type { ExtensionAPI, AgentToolResult } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { join } from "node:path";
import { homedir } from "node:os";
import { readFileSync } from "node:fs";
import { execFileSync } from "node:child_process";

type ToolResult = AgentToolResult<unknown>;
function ok(text: string): ToolResult {
  return { content: [{ type: "text", text }], details: {} };
}

const HOME = homedir();
const THIRD_BRAIN_DIR = join(HOME, "repos", "nikbrunner", "third-brain");
const SCRIPTS_DIR = join(THIRD_BRAIN_DIR, "scripts");

function runScript(script: string, ...args: string[]): string {
  try {
    const result = execFileSync("tsx", [join(SCRIPTS_DIR, script), ...args], {
      encoding: "utf8",
      timeout: 15_000,
      maxBuffer: 1024 * 1024,
      cwd: THIRD_BRAIN_DIR,
    });
    return result.stdout || "";
  } catch (err: unknown) {
    const e = err as { stdout?: string; stderr?: string; message?: string };
    return (e.stdout || "") + (e.stderr || "") || (e.message || "Unknown error");
  }
}

function extractText(content: unknown): string {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    return content
      .filter((c: any) => c.type === "text" && typeof c.text === "string")
      .map((c: any) => c.text)
      .join("\n");
  }
  return "";
}

export default function (pi: ExtensionAPI) {
  let pendingUserMessages: string[] = [];
  let pendingAssistantMessages: string[] = [];

  // ─── Lifecycle ──────────────────────────────────────────────────────

  pi.on("session_start", async (_event, ctx) => {
    try {
      // Run session-start to inject brain context
      const context = runScript("session-start.ts");
      if (context.trim()) {
        ctx.ui.setStatus("third-brain", "🧠 Brain context loaded");
        setTimeout(() => {
          try { ctx.ui.setStatus("third-brain", ""); } catch { /* ctx stale */ }
        }, 3000);
      }
    } catch {
      // Non-critical
    }
  });

  pi.on("before_agent_start", async (event, ctx) => {
    // Inject brain context before the agent processes the user's prompt
    const prompt = event.prompt;
    try {
      const result = execFileSync("tsx", [
        join(SCRIPTS_DIR, "recall.ts"),
        prompt,
        "--limit", "5",
      ], {
        encoding: "utf8",
        timeout: 10_000,
        maxBuffer: 256 * 1024,
        cwd: THIRD_BRAIN_DIR,
      });

      if (result.stdout && result.stdout.trim()) {
        return {
          systemPrompt: `${event.systemPrompt}\n\n<memory>\nRelevant memories from Penny's brain:\n${result.stdout}\n</memory>`,
        };
      }
    } catch {
      // Non-critical — continue without injected context
    }
  });

  pi.on("agent_end", async (event, _ctx) => {
    // Collect messages for consolidation
    for (const msg of event.messages) {
      if (msg.role === "user" && "content" in msg) {
        const text = extractText(msg.content);
        if (text) {
          pendingUserMessages.push(text);
          if (pendingUserMessages.length > 60) pendingUserMessages.shift();
        }
      } else if (msg.role === "assistant" && "content" in msg) {
        const text = extractText(msg.content);
        if (text) {
          pendingAssistantMessages.push(text);
          if (pendingAssistantMessages.length > 60) pendingAssistantMessages.shift();
        }
      }
    }
  });

  pi.on("session_before_switch", async (_event, ctx) => {
    if (pendingUserMessages.length >= 3) {
      ctx.ui.setStatus("third-brain", "🧠 Consolidating...");
      try {
        // Write messages to temp file and call consolidate
        const messages = pendingUserMessages.map((m, i) => ({
          role: "user",
          content: m,
          reply: pendingAssistantMessages[i] || "",
        }));
        const tmpInput = JSON.stringify(messages);
        execFileSync("tsx", [join(SCRIPTS_DIR, "consolidate.ts")], {
          encoding: "utf8",
          timeout: 30_000,
          input: tmpInput,
          cwd: THIRD_BRAIN_DIR,
        });
      } catch {
        // Best-effort
      }
      ctx.ui.setStatus("third-brain", "");
      pendingUserMessages = [];
      pendingAssistantMessages = [];
    }
  });

  pi.on("session_shutdown", async () => {
    if (pendingUserMessages.length >= 3) {
      try {
        const messages = pendingUserMessages.map((m, i) => ({
          role: "user",
          content: m,
          reply: pendingAssistantMessages[i] || "",
        }));
        execFileSync("tsx", [join(SCRIPTS_DIR, "consolidate.ts")], {
          encoding: "utf8",
          timeout: 30_000,
          input: JSON.stringify(messages),
          cwd: THIRD_BRAIN_DIR,
        });
      } catch {
        // Best-effort on shutdown
      }
    }
  });

  // ─── Tools ──────────────────────────────────────────────────────────

  pi.registerTool({
    name: "brain_remember",
    label: "Brain Remember",
    description: "Write a memory to Penny's third-brain. Use for decisions, corrections, personal facts, or project insights worth keeping across sessions.",
    parameters: Type.Object({
      content: Type.String({ description: "The fact, decision, or observation to remember (one sentence)" }),
      type: Type.Optional(Type.String({ description: "Memory type: person, project, pattern, session, self, or daily (default)" })),
      tags: Type.Optional(Type.String({ description: "Comma-separated tags for categorization" })),
    }) as any,
    async execute(_id, params, _signal, _update, _ctx) {
      const result = runScript("remember.ts",
        "--content", params.content,
        "--type", params.type || "daily",
        "--tags", params.tags || "",
      );
      return ok(result || `Remembered: ${params.content}`);
    },
  });

  pi.registerTool({
    name: "brain_recall",
    label: "Brain Recall",
    description: "Search Penny's third-brain for relevant memories, facts, or context.",
    parameters: Type.Object({
      query: Type.String({ description: "Search query" }),
      type: Type.Optional(Type.String({ description: "Filter by type: person, project, pattern, session, self" })),
      limit: Type.Optional(Type.Number({ description: "Max results (default 5)" })),
    }) as any,
    async execute(_id, params, _signal, _update, _ctx) {
      const args = [params.query, "--limit", String(params.limit || 5)];
      if (params.type) args.push("--type", params.type);

      const result = runScript("recall.ts", ...args);
      return ok(result || "No memories found.");
    },
  });

  pi.registerTool({
    name: "brain_forget",
    label: "Brain Forget",
    description: "Remove a memory from Penny's third-brain.",
    parameters: Type.Object({
      file: Type.String({ description: "Brain file path (e.g., people/nik.md)" }),
      match: Type.String({ description: "Text to match for removal" }),
      section: Type.Optional(Type.String({ description: "Section heading to search within" })),
    }) as any,
    async execute(_id, params, _signal, _update, _ctx) {
      const args = ["--file", params.file, "--match", params.match];
      if (params.section) args.push("--section", params.section);

      const result = runScript("forget.ts", ...args);
      return ok(result || `Removed "${params.match}" from ${params.file}`);
    },
  });

  pi.registerTool({
    name: "brain_stats",
    label: "Brain Stats",
    description: "Show third-brain statistics — file counts and types.",
    parameters: Type.Object({}) as any,
    async execute(_id, _params, _signal, _update, _ctx) {
      const result = runScript("sync-index.ts");
      return ok(result || "Brain stats unavailable");
    },
  });
}

