#!/usr/bin/env tsx
// forget.ts — Remove a memory from the brain
// Usage: tsx scripts/forget.ts --file people/nik.md --section "Key Facts" --match "Deno"
//        tsx scripts/forget.ts --file daily/2026-05-10.md --match "something to forget"

import { join } from "node:path";
import { parseArgs } from "node:util";
import { BrainStore } from "./store.js";
import {
  removeFromSection,
  readBrainFile,
  writeBrainFile,
  today,
  dateToString,
  tagsToString,
  extractTitle,
} from "./markdown.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

interface ForgetArgs {
  file: string;
  section?: string;
  match: string;
}

function parseCliArgs(): ForgetArgs {
  const { values } = parseArgs({
    args: process.argv.slice(2),
    options: {
      file: { type: "string" },
      section: { type: "string" },
      match: { type: "string" },
    },
    allowPositionals: true,
  });

  const match = values.match || (values as Record<string, unknown>)._[0] as string;

  if (!values.file || !match) {
    console.error("Error: --file and --match required");
    process.exit(1);
  }

  return {
    file: values.file as string,
    section: values.section as string | undefined,
    match,
  };
}

function removeLines(content: string, match: string): { content: string; removed: number } {
  const lines = content.split("\n");
  const newLines: string[] = [];
  let removed = 0;
  const lowerMatch = match.toLowerCase();

  for (const line of lines) {
    if (line.toLowerCase().includes(lowerMatch)) {
      removed++;
    } else {
      newLines.push(line);
    }
  }

  return { content: newLines.join("\n"), removed };
}

async function forget(args: ForgetArgs): Promise<void> {
  const store = new BrainStore(DB_PATH);

  const file = readBrainFile(args.file);
  if (!file) {
    console.log(`File not found: ${args.file}`);
    store.close();
    return;
  }

  if (args.section) {
    // Remove from a specific section
    const updated = removeFromSection(args.file, args.section, args.match);
    if (updated) {
      store.upsertFile({
        path: updated.path,
        checksum: updated.checksum,
        type: updated.frontmatter.type || "unknown",
        tags: tagsToString(updated.frontmatter.tags || []),
        title: extractTitle(updated.content),
        content: updated.content,
        updated: dateToString(updated.frontmatter.updated) || today(),
        indexed_at: new Date().toISOString(),
      });
      console.log(`Removed "${args.match}" from ${args.file} > ${args.section}`);
    } else {
      console.log(`Not found: "${args.match}" in ${args.file} > ${args.section}`);
    }
  } else {
    // No section — remove matching lines from the entire file
    const { content: newContent, removed } = removeLines(file.content, args.match);

    if (removed === 0) {
      console.log(`Not found: "${args.match}" in ${args.file}`);
      store.close();
      return;
    }

    writeBrainFile(args.file, { ...file.frontmatter, updated: today() }, newContent);
    const updatedFile = readBrainFile(args.file)!;

    store.upsertFile({
      path: updatedFile.path,
      checksum: updatedFile.checksum,
      type: updatedFile.frontmatter.type || "unknown",
      tags: tagsToString(updatedFile.frontmatter.tags || []),
      title: extractTitle(updatedFile.content),
      content: updatedFile.content,
      updated: today(),
      indexed_at: new Date().toISOString(),
    });

    console.log(`Removed ${removed} matching line(s) from ${args.file}`);
  }

  store.close();
}

export async function forgetMemory(
  file: string,
  match: string,
  section?: string
): Promise<boolean> {
  await forget({ file, match, section });
  return true;
}

// CLI entry point
if (import.meta.url === `file://${process.argv[1]}` || process.argv[1]?.endsWith("/forget.ts")) {
  const args = parseCliArgs();
  forget(args).catch(err => {
    console.error("forget failed:", err);
    process.exit(1);
  });
}

